class Solution(object):
    def resultsArray(self, nums, k):
        n = len(nums)
        result = []
        for i in range(n - k + 1):
            sub = nums[i:i+k]
            if all(sub[j] == sub[j-1] + 1 for j in range(1, k)):
                result.append(sub[-1])
            else:
                result.append(-1)
        return result
